import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"水龙神巫女","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/水龙神巫女.md","filePath":"4.资源分区/1.血统与训练/3.心智类/水龙神巫女.md"}'),o={name:"4.资源分区/1.血统与训练/3.心智类/水龙神巫女.md"};function d(_,e,l,p,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"水龙神巫女",tabindex:"-1"},[n("水龙神巫女 "),r("a",{class:"header-anchor",href:"#水龙神巫女","aria-label":'Permalink to "水龙神巫女"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),s('<h1 id="水龙神巫女-1" tabindex="-1">水龙神巫女 <a class="header-anchor" href="#水龙神巫女-1" aria-label="Permalink to &quot;水龙神巫女&quot;">​</a></h1><p>水龙神巫女<br> 魔幻本质<br> 训练<br> 侍奉传说中掌管江海湖水的龙神的巫女，为守护海洋的安宁而踏上旅程。<br> 该资源与信仰一神教的资源互斥。<br> D级：冒失小巫女<br> 作为仅仅接受了训练初出茅庐的你，开始了旅程。<br> 【水龙神术】：你获得D级自然法术派系造诣。<br> 【祭礼剑术】：你获得一种新的施法方式与攻击方式，具有3点基础法术强度，即以决心+武技+剑+能量爆发，当你以此法进行攻击时，表现为你挥动法器发出水流冲击目标，造成寒冷能量伤害，攻击距离15米。<br> 【开灵】：你开启能量池：灵气。（详情查询能量池：灵气）<br> 同时获得一种额外用法：当你受到攻击时，你能让灵气如水游身抵御伤害，消耗1点灵气，获得2点偏斜防御，持续一轮。<br> 【游龙入海】：你具有水下呼吸能力，且具有跟移速相同的游泳速度，这是水龙神的祝福。</p><p>C级：巡海巫女<br> 在旅途中巡礼的巫女，目标是成为守护大海安宁的存在。<br> 【水龙神术熟练】：你获得C级自然法术派系造诣，你使用【祭礼剑术】释放的法术具有【贯穿】<br> 【唤海】：你通过一个自由动作祭礼召唤出无底深海的一份残片，与你身下的区域相连接，在祭礼完成的下一个回合完成后你触及范围内魔法般的变为没有下沉限制的深海环境，这是D级环境效果，持续一天。<br> 【祭礼剑术：对决】：你可以选择使用【专注+专业：剑】代替原本的技能进行格挡<br> 【眠龙入渊】：你获得水龙神的许可，可以在深海畅游自如，你现在获得【三防】</p><p>B级：精英巫女<br> 水龙神为你侧目，你是他的使者，代行他的意志。<br> 【水龙神术精通】：你获得B级自然法术派系造诣，你使用【祭礼剑术】释放的法术攻击具有【8加骰】<br> 【水龙神之半身】：你现在可以以一个标准动作消耗2点灵气进行仪式呼唤水龙神，在下个回合开始在你周围1米召唤一个由不断流动的水流组成的你的形象的法术造物，称为流水半身，其存在持续一个场景。<br> 流水半身无法主动移动，体积、外貌等同于你，与你共享视觉的感知方式和思维，但不增加你的敏感范围且必须处在你的敏感范围内才生效。流水半身没有生命值的概念，所有对她进行的攻击都会导向于你，但射程照常进行结算。水流半身是一个B级别幻象来源的伪装效果，若对方具有相应的免疫，将能够识破水流半身的真实情况。<br> 当你的视觉效果线里存在流水半身时，你可以以流水半身的位置进行【祭礼剑术】的施法，但释放法术的射程需额外减去你与流水半身的距离进行计算。每轮一次，以此法释放的法术进行的法术检定成功数增加一半，你可以一个自由动作遣散流水半身。若水流半身脱离了你的感知线，其将自动消失。<br> （1.轮回者魔恶与流水半身在场上，两者同时遭受到范围攻击，魔恶进行一次受到的伤害结算，然后由于流水半身的效果再进行一次受到伤害结算<br> 2.流水半身受到敌人的近战攻击，同时轮回者魔恶距离流水半身的距离大于敌人的射程，不对魔恶进行伤害结算。<br> 3.流水半身受到敌人的直线型远程攻击，然后转而射向在敌人眼中模糊定位的轮回者魔恶，由于射程足够且可以攻击到，对魔恶进行伤害结算。<br> 4.流水半身受到敌人的直线型远程攻击，然后转而射向躲起来的轮回者魔恶，虽然射程足够但由于不是曲线型攻击不到，不对魔恶进行伤害结算。）</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
